def run_with_retry(operation, policy, max_attempts=3):
    if max_attempts < 1:
        raise ValueError("max_attempts must be positive")
    for attempt in range(1, max_attempts + 1):
        try:
            return operation()
        except Exception as error:
            if policy.classify(type(error)) != "retry" or attempt == max_attempts:
                raise
    raise AssertionError("unreachable")

